using System;
using System.Collections.Generic;

public class AllOne {

    private Dictionary<string, int> countMap;
    private SortedDictionary<int, HashSet<string>> keyMap;
    private int minCount;
    private int maxCount;

    public AllOne() {
        countMap = new Dictionary<string, int>();
        keyMap = new SortedDictionary<int, HashSet<string>>();
        minCount = 0;
        maxCount = 0;
    }

    public void Inc(string key) {
        if (countMap.ContainsKey(key)) {
            int oldCount = countMap[key];
            countMap[key]++;
            int newCount = countMap[key];

            keyMap[oldCount].Remove(key);
            if (keyMap[oldCount].Count == 0) {
                keyMap.Remove(oldCount);
            }

            if (!keyMap.ContainsKey(newCount)) {
                keyMap[newCount] = new HashSet<string>();
            }
            keyMap[newCount].Add(key);

            if (oldCount == minCount && keyMap[oldCount].Count == 0) {
                minCount++;
            }
            if (newCount > maxCount) {
                maxCount = newCount;
            }
        } else {
            countMap[key] = 1;
            if (!keyMap.ContainsKey(1)) {
                keyMap[1] = new HashSet<string>();
            }
            keyMap[1].Add(key);
            minCount = 1;
            maxCount = Math.Max(maxCount, 1);
        }
    }

    public void Dec(string key) {
        if (countMap.ContainsKey(key)) {
            int oldCount = countMap[key];
            if (oldCount == 1) {
                countMap.Remove(key);
                keyMap[oldCount].Remove(key);
                if (keyMap[oldCount].Count == 0) {
                    keyMap.Remove(oldCount);
                }
                if (oldCount == minCount) {
                    if (keyMap.Count > 0) {
                        minCount = keyMap.Keys.GetEnumerator();
                        minCount.MoveNext();
                    } else {
                        minCount = 0;
                    }
                }
                if (oldCount == maxCount) {
                    if (keyMap.Count > 0) {
                        maxCount = keyMap.Keys.GetEnumerator();
                        maxCount.MoveNext();
                    } else {
                        maxCount = 0;
                    }
                }
            } else {
                countMap[key]--;
                int newCount = countMap[key];

                keyMap[oldCount].Remove(key);
                if (keyMap[oldCount].Count == 0) {
                    keyMap.Remove(oldCount);
                }

                if (!keyMap.ContainsKey(newCount)) {
                    keyMap[newCount] = new HashSet<string>();
                }
                keyMap[newCount].Add(key);

                if (oldCount == maxCount && keyMap[oldCount].Count == 0) {
                    maxCount--;
                }
                if (newCount < minCount) {
                    minCount = newCount;
                }
            }
        }
    }

    public string GetMaxKey() {
        if (keyMap.Count == 0) {
            return "";
        }
        return keyMap[keyMap.Keys.GetEnumerator()].GetEnumerator().Current;
    }

    public string GetMinKey() {
        if (keyMap.Count == 0) {
            return "";
        }
        return keyMap[keyMap.Keys.GetEnumerator()].GetEnumerator().Current;
    }
}
